'use client';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ArrowLeft, FolderCog, Plus, Trash2, Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { useFinancialCategories } from "@/hooks/useFinancialCategories";
import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { toast } from "@/hooks/use-toast";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export default function FinancialCategoriesPage() {
    const router = useRouter();
    const {
        categories,
        entradaCategories,
        saidaCategories,
        isLoading,
        createCategory,
        deleteCategory
    } = useFinancialCategories();

    const [isNewCategoryOpen, setIsNewCategoryOpen] = useState(false);
    const [newCategoryName, setNewCategoryName] = useState("");
    const [newCategoryType, setNewCategoryType] = useState<"entrada" | "saida">("entrada");
    const [newCategoryColor, setNewCategoryColor] = useState("#10b981");
    const [categoryToDelete, setCategoryToDelete] = useState<{ id: string; name: string } | null>(null);

    const handleCreateCategory = () => {
        if (!newCategoryName.trim()) {
            toast({
                variant: "destructive",
                title: "Erro",
                description: "Nome da categoria é obrigatório"
            });
            return;
        }

        createCategory.mutate({
            name: newCategoryName.trim(),
            type: newCategoryType,
            color: newCategoryColor
        }, {
            onSuccess: () => {
                setIsNewCategoryOpen(false);
                setNewCategoryName("");
                setNewCategoryType("entrada");
                setNewCategoryColor("#10b981");
            }
        });
    };

    const handleDeleteCategory = async () => {
        if (categoryToDelete) {
            await deleteCategory.mutateAsync(categoryToDelete.id);
            setCategoryToDelete(null);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-emerald-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={() => router.push('/financial')}>
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold text-foreground">Categorias Financeiras</h1>
                        <p className="text-muted-foreground">Gerencie as categorias de receitas e despesas</p>
                    </div>
                </div>
                <Button
                    className="bg-emerald-500 hover:bg-emerald-600"
                    onClick={() => setIsNewCategoryOpen(true)}
                >
                    <Plus className="h-4 w-4 mr-2" />
                    Nova Categoria
                </Button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Income Categories */}
                <Card className="border-emerald-500/20 bg-gradient-to-br from-emerald-500/5 to-transparent">
                    <CardHeader>
                        <CardTitle className="text-emerald-500 flex items-center gap-2">
                            <FolderCog className="h-5 w-5" />
                            Categorias de Receita
                        </CardTitle>
                        <CardDescription>Categorias para entradas e receitas</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-2">
                        {entradaCategories.length === 0 ? (
                            <p className="text-muted-foreground text-sm py-4 text-center">
                                Nenhuma categoria de receita cadastrada
                            </p>
                        ) : (
                            entradaCategories.map((cat) => (
                                <div
                                    key={cat.id}
                                    className="flex items-center justify-between p-3 bg-muted/30 rounded-lg hover:bg-muted/50 transition-colors"
                                >
                                    <div className="flex items-center gap-3">
                                        <div
                                            className="w-4 h-4 rounded-full"
                                            style={{ backgroundColor: cat.color || '#10b981' }}
                                        />
                                        <span className="font-medium">{cat.name}</span>
                                    </div>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        className="h-8 w-8 text-red-500 hover:text-red-600 hover:bg-red-500/10"
                                        onClick={() => setCategoryToDelete({ id: cat.id, name: cat.name })}
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>

                {/* Expense Categories */}
                <Card className="border-red-500/20 bg-gradient-to-br from-red-500/5 to-transparent">
                    <CardHeader>
                        <CardTitle className="text-red-500 flex items-center gap-2">
                            <FolderCog className="h-5 w-5" />
                            Categorias de Despesa
                        </CardTitle>
                        <CardDescription>Categorias para saídas e despesas</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-2">
                        {saidaCategories.length === 0 ? (
                            <p className="text-muted-foreground text-sm py-4 text-center">
                                Nenhuma categoria de despesa cadastrada
                            </p>
                        ) : (
                            saidaCategories.map((cat) => (
                                <div
                                    key={cat.id}
                                    className="flex items-center justify-between p-3 bg-muted/30 rounded-lg hover:bg-muted/50 transition-colors"
                                >
                                    <div className="flex items-center gap-3">
                                        <div
                                            className="w-4 h-4 rounded-full"
                                            style={{ backgroundColor: cat.color || '#ef4444' }}
                                        />
                                        <span className="font-medium">{cat.name}</span>
                                    </div>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        className="h-8 w-8 text-red-500 hover:text-red-600 hover:bg-red-500/10"
                                        onClick={() => setCategoryToDelete({ id: cat.id, name: cat.name })}
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>
            </div>

            {/* New Category Modal */}
            <Dialog open={isNewCategoryOpen} onOpenChange={setIsNewCategoryOpen}>
                <DialogContent className="sm:max-w-md">
                    <DialogHeader>
                        <DialogTitle>Nova Categoria</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        <div className="space-y-2">
                            <Label>Nome da Categoria</Label>
                            <Input
                                value={newCategoryName}
                                onChange={(e) => setNewCategoryName(e.target.value)}
                                placeholder="Ex: Consultas, Aluguel..."
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Tipo</Label>
                            <Select value={newCategoryType} onValueChange={(v) => setNewCategoryType(v as "entrada" | "saida")}>
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="entrada">Receita (Entrada)</SelectItem>
                                    <SelectItem value="saida">Despesa (Saída)</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label>Cor</Label>
                            <div className="flex items-center gap-3">
                                <div
                                    className="w-10 h-10 rounded-full border-2 border-border cursor-pointer overflow-hidden"
                                    style={{ backgroundColor: newCategoryColor }}
                                >
                                    <input
                                        type="color"
                                        value={newCategoryColor}
                                        onChange={(e) => setNewCategoryColor(e.target.value)}
                                        className="w-full h-full opacity-0 cursor-pointer"
                                    />
                                </div>
                                <Input
                                    value={newCategoryColor}
                                    onChange={(e) => setNewCategoryColor(e.target.value)}
                                    className="flex-1 uppercase"
                                    maxLength={7}
                                />
                            </div>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsNewCategoryOpen(false)}>Cancelar</Button>
                        <Button
                            onClick={handleCreateCategory}
                            disabled={createCategory.isPending}
                            className="bg-emerald-500 hover:bg-emerald-600"
                        >
                            {createCategory.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                            Criar Categoria
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Delete Confirmation */}
            <AlertDialog open={!!categoryToDelete} onOpenChange={(open) => !open && setCategoryToDelete(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Excluir categoria?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Tem certeza que deseja excluir a categoria &quot;{categoryToDelete?.name}&quot;?
                            Categorias com transações associadas não podem ser excluídas.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancelar</AlertDialogCancel>
                        <AlertDialogAction
                            className="bg-red-500 hover:bg-red-600"
                            onClick={handleDeleteCategory}
                        >
                            Excluir
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    );
}
